// Generated by OrchestKit Claude Plugin
// Created: 2026-04-23

/**
 * PostTool Metrics Dispatcher — Issue #1489 (M121)
 *
 * Collapses the three async hooks that fire on the PostToolUse catchall
 * matcher into a single subprocess invocation. Same behavior, same files
 * written, same semantics — just one node cold-start per event instead
 * of three.
 *
 * Handlers orchestrated (all preserve their existing side effects):
 *   1. webhookForwarder   — emits event to registered telemetry sinks
 *   2. metricsBridge      — per-session ork-metrics-{session}.json
 *   3. contextCrossingWarn — token-budget threshold check + image log
 *
 * Failure isolation: Promise.allSettled — one handler throwing does not
 * prevent the others from completing. Logged via ctx.log, never propagated
 * so CC does not see a hook failure for telemetry.
 *
 * Hooks.json change:
 *   BEFORE: 3 separate `{ type: "command", command: run-hook.mjs X }` entries
 *           spawn 3 node subprocesses per PostToolUse event
 *   AFTER:  1 `{ type: "command", command: run-hook.mjs posttool/metrics-
 *           dispatcher }` — spawns 1 subprocess that calls 3 handlers
 *           in-process.
 *
 * On a session with 200 tool calls: 600 subprocess spawns → 200. Same
 * telemetry output, ~3x fewer node cold-starts on the catchall path.
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

// Lazy imports keep the metrics-dispatcher module small when loaded —
// the inner handlers are pulled in at call time. This lets unit tests
// mock each handler independently via vi.mock without the dispatcher
// needing to know about any of them at module-scope.
import { webhookForwarder } from '../lifecycle/webhook-forwarder.js';
import { metricsBridge } from './metrics-bridge.js';
import { contextCrossingWarn } from './context-crossing-warn.js';

const HOOK_NAME = 'posttool/metrics-dispatcher';

type DispatcherHandler = (
  input: HookInput,
  ctx: HookContext,
) => HookResult | Promise<HookResult>;

/**
 * Exported for tests — the canonical list of handlers the dispatcher fans
 * out to, in registration order. The dispatcher runs them via
 * Promise.allSettled so ordering doesn't matter for correctness; it only
 * matters for reproducible logs.
 */
export const DISPATCHER_HANDLERS: ReadonlyArray<{
  name: string;
  fn: DispatcherHandler;
}> = [
  { name: 'webhookForwarder', fn: webhookForwarder },
  { name: 'metricsBridge', fn: metricsBridge },
  { name: 'contextCrossingWarn', fn: contextCrossingWarn },
];

export async function metricsDispatcher(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): Promise<HookResult> {
  const results = await Promise.allSettled(
    DISPATCHER_HANDLERS.map(async ({ name, fn }) => {
      try {
        return await fn(input, ctx);
      } catch (err) {
        const msg = err instanceof Error ? err.message : String(err);
        ctx.log(HOOK_NAME, `${name} threw: ${msg}`, 'warn');
        throw err;
      }
    }),
  );

  // Surface a summary log so production can see handler-level health
  const failed = results.filter(r => r.status === 'rejected').length;
  if (failed > 0) {
    ctx.log(
      HOOK_NAME,
      `${failed}/${DISPATCHER_HANDLERS.length} handlers failed (telemetry best-effort, continuing)`,
      'warn',
    );
  }

  // Collect any additionalContext from inner handlers — primarily
  // contextCrossingWarn which emits a one-shot crossing warning.
  // If multiple handlers emit context (unusual), concatenate with separator.
  const contexts: string[] = [];
  for (const r of results) {
    if (r.status !== 'fulfilled') continue;
    const added = r.value?.hookSpecificOutput?.additionalContext;
    if (typeof added === 'string' && added.trim()) {
      contexts.push(added);
    }
  }

  if (contexts.length === 0) {
    return outputSilentSuccess();
  }

  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      hookEventName: 'PostToolUse',
      additionalContext: contexts.join('\n\n'),
    },
  };
}

export default metricsDispatcher;
